script:
frappe.ui.form.on('Customer', {
	refresh: function(frm) {
		// Add Call button to toolbar
		frm.add_custom_button(
			'<svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor" style="vertical-align:middle;margin-right:4px;"><path fill-rule="evenodd" clip-rule="evenodd" d="M2.67754 2.70675C2.53628 2.84008 2.44787 3.03363 2.46988 3.29885C2.47828 3.40004 2.4869 3.50717 2.49497 3.61981C2.63494 4.75003 2.9076 5.83579 3.29638 6.82863L4.1395 6.29907C5.02533 5.74269 5.45257 4.67951 5.19805 3.66489L4.98918 2.83225C4.93526 2.61729 4.74204 2.46656 4.52043 2.46656H3.36772C3.06265 2.46656 2.82575 2.56686 2.67754 2.70675ZM3.69508 7.71962L4.6536 7.11757C5.89375 6.33864 6.49189 4.85019 6.13556 3.42971L5.9267 2.59708C5.76493 1.9522 5.18528 1.5 4.52043 1.5H3.36772C2.85467 1.5 2.368 1.66981 2.01409 2.00386C1.65323 2.34447 1.46097 2.82869 1.50663 3.3788C1.51521 3.48212 1.52381 3.58915 1.53174 3.70087L1.53262 3.71327L1.53414 3.72561C1.70903 5.14795 2.08181 6.51379 2.62992 7.73832C2.8107 8.1422 3.76654 10.0804 5.03876 11.2498C6.27205 12.3833 6.85696 12.7556 8.29758 13.4488L8.31072 13.4551L8.32421 13.4606C9.77742 14.0548 11.0901 14.3742 12.5272 14.4965C13.6361 14.5909 14.4998 13.677 14.4998 12.6231V11.5096C14.4998 10.8539 14.0598 10.2799 13.4267 10.1095L12.6539 9.90153C11.1864 9.50659 9.63455 10.1384 8.86371 11.4495C8.67966 11.7625 8.49178 12.0826 8.3163 12.3822C7.24188 11.8473 6.72935 11.4908 5.69284 10.5382C4.79599 9.71382 4.04577 8.4042 3.69508 7.71962ZM9.21019 12.7685C10.3726 13.198 11.4466 13.4344 12.6092 13.5334C13.096 13.5749 13.5332 13.1706 13.5332 12.6231V11.5096C13.5332 11.291 13.3866 11.0997 13.1755 11.0429L12.4027 10.8349C11.3541 10.5527 10.2467 11.0044 9.69692 11.9394C9.53381 12.2168 9.3678 12.4995 9.21019 12.7685Z"/></svg> Call',
			function() {
				var defaultNumber = frm.doc.custom_mobile || '';
				// Show dialog to confirm number — same pattern as CRM Lead
				var d = new frappe.ui.Dialog({
					title: 'Make a call',
					fields: [
						{
							fieldtype: 'Data',
							fieldname: 'destination_number',
							label: 'Destination Number',
							default: defaultNumber,
							reqd: 1
						}
					],
					primary_action_label: 'Call',
					primary_action: function(values) {
						var num = values.destination_number;
						if (!num) {
							frappe.msgprint('Please enter a destination number');
							return;
						}
						frappe.call({
							method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.click_to_call',
							args: { destination_number: num },
							callback: function(r) {
								d.hide();
								showCallWidget(num, r.message, null, frappe.call);
							}
						});
					}
				});
				d.show();
			}
		);

		// Check for active calls on page load — resume widget if agent is on a call
		checkForActiveCalls(frappe.call);
	}
});

// ── Poll for incoming/active calls ───────────────────────────────────────────

var _customerCallShownIds = new Set();
var _customerCallPollTimer = null;

function checkForActiveCalls(call) {
	if (_customerCallPollTimer) return;

	function poll() {
		if (document.getElementById('smartflo-call-widget')) return;

		frappe.call({
			method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls',
			args: {},
			callback: function(r) {
				var data = r.message;
				if (!data || !data.agent_number) return;
				var liveCalls = Array.isArray(data.data) ? data.data : [];

				for (var i = 0; i < liveCalls.length; i++) {
					var c = liveCalls[i];
					var cid = c.call_id;
					if (!cid || _customerCallShownIds.has(cid)) continue;
					_customerCallShownIds.add(cid);
					var callerNumber = c.customer_number || c.source || '';
					showCallWidget(callerNumber, null, c, call);
					break;
				}
			}
		});
	}

	_customerCallPollTimer = setInterval(poll, 2500);
	poll();
}

// ── Live Call Widget ──────────────────────────────────────────────────────────

function showCallWidget(destinationNumber, clickToCallResponse, activeCallData, call) {
	var existing = document.getElementById('smartflo-call-widget');
	if (existing) existing.remove();

	var pollTimer = null;
	var tickTimer = null;
	var callId = null;
	var state = 'connecting';

	// If resuming an existing call, seed call_id and state from it
	if (activeCallData) {
		callId = activeCallData.call_id || null;
		var apiState0 = (activeCallData.state || '').toLowerCase();
		if (apiState0.includes('answer') || apiState0.includes('bridge')) {
			state = 'answered';
		} else if (apiState0.includes('ring') || apiState0.includes('dial')) {
			state = 'ringing';
		} else {
			state = 'answered';
		}
	}

	// Try to extract call_id from click_to_call response
	if (!callId && clickToCallResponse && clickToCallResponse.data) {
		var respData = clickToCallResponse.data;
		callId = respData.call_id || respData.callid || respData.id || null;
	}

	var phoneIconSvg = '<svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor"><path fill-rule="evenodd" clip-rule="evenodd" d="M2.67754 2.70675C2.53628 2.84008 2.44787 3.03363 2.46988 3.29885C2.47828 3.40004 2.4869 3.50717 2.49497 3.61981C2.63494 4.75003 2.9076 5.83579 3.29638 6.82863L4.1395 6.29907C5.02533 5.74269 5.45257 4.67951 5.19805 3.66489L4.98918 2.83225C4.93526 2.61729 4.74204 2.46656 4.52043 2.46656H3.36772C3.06265 2.46656 2.82575 2.56686 2.67754 2.70675ZM3.69508 7.71962L4.6536 7.11757C5.89375 6.33864 6.49189 4.85019 6.13556 3.42971L5.9267 2.59708C5.76493 1.9522 5.18528 1.5 4.52043 1.5H3.36772C2.85467 1.5 2.368 1.66981 2.01409 2.00386C1.65323 2.34447 1.46097 2.82869 1.50663 3.3788C1.51521 3.48212 1.52381 3.58915 1.53174 3.70087L1.53262 3.71327L1.53414 3.72561C1.70903 5.14795 2.08181 6.51379 2.62992 7.73832C2.8107 8.1422 3.76654 10.0804 5.03876 11.2498C6.27205 12.3833 6.85696 12.7556 8.29758 13.4488L8.31072 13.4551L8.32421 13.4606C9.77742 14.0548 11.0901 14.3742 12.5272 14.4965C13.6361 14.5909 14.4998 13.677 14.4998 12.6231V11.5096C14.4998 10.8539 14.0598 10.2799 13.4267 10.1095L12.6539 9.90153C11.1864 9.50659 9.63455 10.1384 8.86371 11.4495C8.67966 11.7625 8.49178 12.0826 8.3163 12.3822C7.24188 11.8473 6.72935 11.4908 5.69284 10.5382C4.79599 9.71382 4.04577 8.4042 3.69508 7.71962ZM9.21019 12.7685C10.3726 13.198 11.4466 13.4344 12.6092 13.5334C13.096 13.5749 13.5332 13.1706 13.5332 12.6231V11.5096C13.5332 11.291 13.3866 11.0997 13.1755 11.0429L12.4027 10.8349C11.3541 10.5527 10.2467 11.0044 9.69692 11.9394C9.53381 12.2168 9.3678 12.4995 9.21019 12.7685Z"/></svg>';

	if (!document.getElementById('smartflo-call-styles')) {
		var styleEl = document.createElement('style');
		styleEl.id = 'smartflo-call-styles';
		styleEl.textContent = '@keyframes cw-enter{from{opacity:0;transform:translateY(8px) scale(0.97)}}'
			+ '@keyframes cw-pulse{0%,100%{opacity:1}50%{opacity:0.35}}'
			+ '@keyframes cw-blink{0%,100%{opacity:1}50%{opacity:0}}'
			+ '.cw-enter{animation:cw-enter 0.35s cubic-bezier(0.16,1,0.3,1) both}'
			+ '.cw-pulse{animation:cw-pulse 2s ease-in-out infinite}'
			+ '.cw-blink{animation:cw-blink 1s ease-in-out 6}'
			+ '.cw-hangup-icon{transform:rotate(135deg)}'
			+ '#smartflo-call-widget *{box-sizing:border-box}'
			+ '#smartflo-expanded{background:#2c2c2c;border-radius:10px;padding:10px 14px 14px;width:280px;box-shadow:0 8px 32px rgba(0,0,0,0.4);color:#ccc;font-family:inherit}'
			+ '#smartflo-pill{background:#2c2c2c;border-radius:999px;padding:7px 10px;box-shadow:0 4px 16px rgba(0,0,0,0.3);color:#ccc;font-family:inherit}';
		document.head.appendChild(styleEl);
	}

	var isMinimized = false;
	var statusText = state === 'answered' ? 'In progress' : state === 'ringing' ? 'Ringing...' : 'Calling...';
	var greenColor = 'rgb(48,166,109)';
	var initialDuration = '--:--';
	if (activeCallData && activeCallData.call_time) {
		var pts = activeCallData.call_time.split(':');
		initialDuration = (pts.length === 3 && pts[0] === '00') ? pts[1] + ':' + pts[2] : activeCallData.call_time;
	}

	var widget = document.createElement('div');
	widget.id = 'smartflo-call-widget';
	widget.style.cssText = 'position:fixed;bottom:24px;right:24px;z-index:99999;transition:opacity 0.3s;';

	var expanded = document.createElement('div');
	expanded.id = 'smartflo-expanded';
	expanded.className = 'cw-enter';
	expanded.innerHTML =
		'<div id="smartflo-drag-handle" style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;cursor:move;user-select:none;">'
		+ '<div style="display:flex;align-items:center;gap:8px;flex:1;min-width:0;">'
		+ '<div style="width:32px;height:32px;border-radius:50%;background:#444;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
		+ '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>'
		+ '</div>'
		+ '<div style="flex:1;min-width:0;">'
		+ '<div style="font-size:13px;font-weight:600;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + destinationNumber + '</div>'
		+ '<div style="display:flex;align-items:center;gap:5px;margin-top:2px;">'
		+ '<div id="smartflo-dot" class="cw-pulse" style="width:6px;height:6px;border-radius:50%;background:' + greenColor + ';flex-shrink:0;"></div>'
		+ '<span id="smartflo-call-status" style="font-size:11px;color:' + greenColor + ';">' + statusText + '</span>'
		+ '</div></div></div>'
		+ '<button id="smartflo-minimize-btn" style="width:26px;height:26px;border-radius:6px;border:none;background:transparent;cursor:pointer;display:flex;align-items:center;justify-content:center;color:#aaa;flex-shrink:0;">'
		+ '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M5 12h14"/></svg>'
		+ '</button></div>'
		+ '<div style="display:flex;flex-direction:column;align-items:center;padding:16px 0 8px;">'
		+ '<div style="width:48px;height:48px;border-radius:50%;background:#444;display:flex;align-items:center;justify-content:center;">'
		+ '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>'
		+ '</div>'
		+ '<div style="font-size:12px;color:#888;margin-top:6px;">' + destinationNumber + '</div>'
		+ '</div>'
		+ '<div id="smartflo-call-duration" style="text-align:center;font-size:13px;color:#888;padding-bottom:12px;font-variant-numeric:tabular-nums;">' + initialDuration + '</div>'
		+ '<div style="display:flex;justify-content:center;padding-bottom:4px;">'
		+ '<button id="smartflo-hangup-btn" style="width:42px;height:42px;border-radius:50%;background:#c0392b;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;color:#fff;">'
		+ '<span class="cw-hangup-icon" style="display:flex;">' + phoneIconSvg + '</span>'
		+ '</button></div>';

	var pill = document.createElement('div');
	pill.id = 'smartflo-pill';
	pill.className = 'cw-enter';
	pill.style.cssText = 'display:none;align-items:center;gap:6px;cursor:pointer;';
	pill.innerHTML =
		'<div style="width:20px;height:20px;border-radius:50%;background:#444;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
		+ '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>'
		+ '</div>'
		+ '<span id="smartflo-pill-number" style="font-size:11px;color:#fff;white-space:nowrap;max-width:110px;overflow:hidden;text-overflow:ellipsis;">' + destinationNumber + '</span>'
		+ '<span style="font-size:11px;color:#666;">&middot;</span>'
		+ '<span id="smartflo-pill-duration" style="font-size:11px;color:#888;font-variant-numeric:tabular-nums;">' + initialDuration + '</span>'
		+ '<button id="smartflo-pill-hangup" style="width:22px;height:22px;border-radius:50%;background:#c0392b;border:none;cursor:pointer;margin-left:2px;display:flex;align-items:center;justify-content:center;color:#fff;flex-shrink:0;">'
		+ '<span class="cw-hangup-icon" style="display:flex;"><svg width="10" height="10" viewBox="0 0 16 16" fill="currentColor"><path fill-rule="evenodd" clip-rule="evenodd" d="M2.67754 2.70675C2.53628 2.84008 2.44787 3.03363 2.46988 3.29885C2.47828 3.40004 2.4869 3.50717 2.49497 3.61981C2.63494 4.75003 2.9076 5.83579 3.29638 6.82863L4.1395 6.29907C5.02533 5.74269 5.45257 4.67951 5.19805 3.66489L4.98918 2.83225C4.93526 2.61729 4.74204 2.46656 4.52043 2.46656H3.36772C3.06265 2.46656 2.82575 2.56686 2.67754 2.70675ZM3.69508 7.71962L4.6536 7.11757C5.89375 6.33864 6.49189 4.85019 6.13556 3.42971L5.9267 2.59708C5.76493 1.9522 5.18528 1.5 4.52043 1.5H3.36772C2.85467 1.5 2.368 1.66981 2.01409 2.00386C1.65323 2.34447 1.46097 2.82869 1.50663 3.3788C1.51521 3.48212 1.52381 3.58915 1.53174 3.70087L1.53262 3.71327L1.53414 3.72561C1.70903 5.14795 2.08181 6.51379 2.62992 7.73832C2.8107 8.1422 3.76654 10.0804 5.03876 11.2498C6.27205 12.3833 6.85696 12.7556 8.29758 13.4488L8.31072 13.4551L8.32421 13.4606C9.77742 14.0548 11.0901 14.3742 12.5272 14.4965C13.6361 14.5909 14.4998 13.677 14.4998 12.6231V11.5096C14.4998 10.8539 14.0598 10.2799 13.4267 10.1095L12.6539 9.90153C11.1864 9.50659 9.63455 10.1384 8.86371 11.4495C8.67966 11.7625 8.49178 12.0826 8.3163 12.3822C7.24188 11.8473 6.72935 11.4908 5.69284 10.5382C4.79599 9.71382 4.04577 8.4042 3.69508 7.71962ZM9.21019 12.7685C10.3726 13.198 11.4466 13.4344 12.6092 13.5334C13.096 13.5749 13.5332 13.1706 13.5332 12.6231V11.5096C13.5332 11.291 13.3866 11.0997 13.1755 11.0429L12.4027 10.8349C11.3541 10.5527 10.2467 11.0044 9.69692 11.9394C9.53381 12.2168 9.3678 12.4995 9.21019 12.7685Z"/></svg></span>'
		+ '</button>';

	widget.appendChild(expanded);
	widget.appendChild(pill);
	document.body.appendChild(widget);

	// ── Minimize / Expand toggle ──
	function toggleMinimize() {
		isMinimized = !isMinimized;
		expanded.style.display = isMinimized ? 'none' : '';
		pill.style.display = isMinimized ? 'flex' : 'none';
	}
	document.getElementById('smartflo-minimize-btn').addEventListener('click', toggleMinimize);
	pill.addEventListener('click', function(e) {
		if (e.target.closest('#smartflo-pill-hangup')) return;
		toggleMinimize();
	});

	// ── Drag to reposition ──
	var isDragging = false;
	var dragStartX = 0, dragStartY = 0, widgetStartX = 0, widgetStartY = 0;
	var dragHandle = document.getElementById('smartflo-drag-handle');
	dragHandle.addEventListener('mousedown', function(e) {
		if (e.target.closest('#smartflo-minimize-btn')) return;
		isDragging = true;
		dragStartX = e.clientX; dragStartY = e.clientY;
		var rect = widget.getBoundingClientRect();
		widgetStartX = rect.left; widgetStartY = rect.top;
		widget.style.bottom = 'auto'; widget.style.right = 'auto';
		widget.style.left = widgetStartX + 'px'; widget.style.top = widgetStartY + 'px';
		e.preventDefault();
	});
	document.addEventListener('mousemove', function(e) {
		if (!isDragging) return;
		widget.style.left = (widgetStartX + (e.clientX - dragStartX)) + 'px';
		widget.style.top = (widgetStartY + (e.clientY - dragStartY)) + 'px';
	});
	document.addEventListener('mouseup', function() { isDragging = false; });

	// ── Duration timer ──
	var lastKnownSeconds = 0;
	var lastSyncedAt = 0;

	function parseCallTime(callTime) {
		var parts = (callTime || '').split(':').map(Number);
		if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
		if (parts.length === 2) return parts[0] * 60 + parts[1];
		return 0;
	}

	function formatDuration(totalSeconds) {
		var hrs = Math.floor(totalSeconds / 3600);
		var mins = Math.floor((totalSeconds % 3600) / 60);
		var secs = totalSeconds % 60;
		var mm = String(mins).padStart(2, '0');
		var ss = String(secs).padStart(2, '0');
		return hrs > 0 ? hrs + ':' + mm + ':' + ss : mm + ':' + ss;
	}

	function syncFromApi(callTime) {
		lastKnownSeconds = parseCallTime(callTime);
		lastSyncedAt = Date.now();
		if (!tickTimer) {
			tickTimer = setInterval(function() {
				var elapsed = Math.floor((Date.now() - lastSyncedAt) / 1000);
				var text = formatDuration(lastKnownSeconds + elapsed);
				var durationEl = document.getElementById('smartflo-call-duration');
				if (durationEl) durationEl.textContent = text;
				var pillDur = document.getElementById('smartflo-pill-duration');
				if (pillDur) pillDur.textContent = text;
			}, 1000);
		}
	}

	// Seed from activeCallData if resuming
	if (activeCallData && activeCallData.call_time && state === 'answered') {
		syncFromApi(activeCallData.call_time);
	}

	// ── Find our call in poll results ──
	function findOurCall(liveCalls) {
		for (var i = 0; i < liveCalls.length; i++) {
			var c = liveCalls[i];
			if (callId && c.call_id === callId) return c;
		}
		for (var j = 0; j < liveCalls.length; j++) {
			var lc = liveCalls[j];
			var dest = lc.customer_number || lc.destination || '';
			var destDigits = dest.replace(/\D/g, '').slice(-10);
			var ourDigits = destinationNumber.replace(/\D/g, '').slice(-10);
			if (destDigits && ourDigits && destDigits === ourDigits) {
				if (!callId) callId = lc.call_id;
				return lc;
			}
		}
		return null;
	}

	// ── Poll for live call status ──
	function pollCallStatus() {
		frappe.call({
			method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls',
			args: {},
			callback: function(r) {
				var statusEl = document.getElementById('smartflo-call-status');
				if (!statusEl) { stopPolling(); return; }

				var data = r.message;
				var liveCalls = [];
				if (data && data.data) {
					if (Array.isArray(data.data)) liveCalls = data.data;
					else if (data.data && Array.isArray(data.data.data)) liveCalls = data.data.data;
				}

				var ourCall = findOurCall(liveCalls);
				var dotEl = document.getElementById('smartflo-dot');

				if (ourCall) {
					var apiState = (ourCall.state || '').toLowerCase();
					if (apiState.includes('answer') || apiState.includes('bridge')) {
						state = 'answered';
						statusEl.textContent = 'In progress';
						statusEl.style.color = greenColor;
						if (dotEl) dotEl.style.background = greenColor;
						if (ourCall.call_time) syncFromApi(ourCall.call_time);
					} else if (apiState.includes('ring') || apiState.includes('dial')) {
						state = 'ringing';
						statusEl.textContent = 'Ringing...';
						statusEl.style.color = greenColor;
						if (dotEl) dotEl.style.background = greenColor;
					} else {
						statusEl.textContent = ourCall.state || 'Active';
						statusEl.style.color = '#999';
					}
				} else if (state === 'answered' || state === 'ringing') {
					endCall('Call Ended');
				}
			}
		});
	}

	pollTimer = setInterval(pollCallStatus, 4000);
	setTimeout(pollCallStatus, 2000);

	// ── Hangup ──
	function doHangup(btn) {
		if (btn) { btn.disabled = true; btn.style.opacity = '0.5'; btn.style.cursor = 'not-allowed'; }
		if (callId) {
			frappe.call({
				method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.hangup_call',
				args: { call_id: callId },
				callback: function() { endCall('Call ended'); }
			});
		} else {
			endCall('Call ended');
		}
	}

	document.getElementById('smartflo-hangup-btn').addEventListener('click', function(e) { doHangup(e.currentTarget); });
	document.getElementById('smartflo-pill-hangup').addEventListener('click', function(e) { e.stopPropagation(); doHangup(e.currentTarget); });

	// ── End call ──
	function endCall(message) {
		stopPolling();
		var redColor = 'rgb(181,42,42)';
		var statusEl = document.getElementById('smartflo-call-status');
		if (statusEl) { statusEl.textContent = message; statusEl.style.color = redColor; statusEl.classList.add('cw-blink'); }
		var dotEl = document.getElementById('smartflo-dot');
		if (dotEl) { dotEl.style.background = redColor; dotEl.className = ''; }
		var hangup = document.getElementById('smartflo-hangup-btn');
		if (hangup) hangup.style.display = 'none';
		var pillHangup = document.getElementById('smartflo-pill-hangup');
		if (pillHangup) pillHangup.style.display = 'none';
		var pillDur = document.getElementById('smartflo-pill-duration');
		if (pillDur) { pillDur.textContent = message; pillDur.style.color = redColor; }
		setTimeout(function() {
			var w = document.getElementById('smartflo-call-widget');
			if (w) { w.style.opacity = '0'; setTimeout(function() { w.remove(); }, 300); }
		}, 3000);
	}

	function stopPolling() {
		if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
		if (tickTimer) { clearInterval(tickTimer); tickTimer = null; }
	}
}

