frappe.ui.form.on('Insurance Renewal Record', {
    refresh(frm) {
        // Verify Renewal MIS button
        if (frm.doc.mis_status !== 'Approved') {
            frm.add_custom_button('Verify Renewal MIS', () => {
                if (!frm.doc.new_policy_number) {
                    frappe.msgprint('Please fill New Policy Number before verifying.');
                    return;
                }
                frappe.confirm(
                    `Confirm new policy <b>${frm.doc.new_policy_number}</b> is verified in the insurer portal?`,
                    () => {
                        frappe.call({
                            method: 'aionion_custom.aionion_custom.controllers.crm_lead.approve_renewal_mis',
                            args: { record_name: frm.doc.name },
                            callback(r) {
                                if (!r.exc) {
                                    frappe.show_alert({ message: 'Renewal MIS Verified!', indicator: 'green' });
                                    frm.reload_doc();
                                }
                            }
                        });
                    }
                );
            }, 'MIS Actions');
        }

        // Reject Renewal MIS button
        if (frm.doc.mis_status !== 'Rejected') {
            frm.add_custom_button('Reject Renewal MIS', () => {
                frappe.prompt(
                    [{ label: 'Reason', fieldname: 'reason', fieldtype: 'Small Text' }],
                    (values) => {
                        frappe.call({
                            method: 'aionion_custom.aionion_custom.controllers.crm_lead.reject_renewal_mis',
                            args: { record_name: frm.doc.name, reason: values.reason },
                            callback(r) {
                                if (!r.exc) {
                                    frappe.show_alert({ message: 'Renewal MIS Rejected.', indicator: 'red' });
                                    frm.reload_doc();
                                }
                            }
                        });
                    },
                    'Reject Reason', 'Reject'
                );
            }, 'MIS Actions');
        }

        // Show MIS status as indicator
        if (frm.doc.mis_status === 'Approved') {
            frm.page.set_indicator('MIS Approved', 'green');
        } else if (frm.doc.mis_status === 'Rejected') {
            frm.page.set_indicator('MIS Rejected', 'red');
        } else {
            frm.page.set_indicator('Pending MIS', 'orange');
        }
    }
});
